SELECT
  DATE(tOrders.created_at) AS date_utc_offset,
  tOrders.id,
  tOrders.user_id,
  tOrders.status,
  tOrders.place_id,
  tStores.name AS store_name,
  tStores.distribution_centre AS dc,
  tStores.chain.name AS store_type,
  tOrders.price.captured_price.total_price,
  product.picking_status,
  product.collected_product.gtin,
  tProducts.name AS product_name,
  LOWER(tProducts.brand) AS product_brand,
  tProducts.categories[
    OFFSET((
      SELECT OFFSET
      FROM UNNEST(categories) cat WITH OFFSET
      WHERE cat.tree_name = "SPAR"
        AND cat.level = 1
    ))
  ].name AS category_level_1,
  tProducts.categories[
    OFFSET((
      SELECT OFFSET
      FROM UNNEST(categories) cat WITH OFFSET
      WHERE cat.tree_name = "SPAR"
        AND cat.level = 2
    ))
  ].name AS category_level_2,
  product.collected_product.quantity,
  (product.collected_product.row_price_vat / 
    (1 + (product.collected_product.vat_percentage / 100))
  ) AS row_price_vat,
  product.collected_product.vat_percentage

FROM `naveo_api_dataset.naveo_order_data_min` tOrders
CROSS JOIN UNNEST(products) product

LEFT JOIN `naveo_api_dataset.naveo_store_list_min` tStores
  ON tStores.master_id = tOrders.place_id

LEFT JOIN `naveo_api_dataset.naveo_products` tProducts
  ON CAST(tProducts.gtin AS INT64) = product.collected_product.gtin

WHERE
  DATE(tOrders.created_at, "Africa/Johannesburg")
    BETWEEN PARSE_DATE("%Y%m%d", "20250101")
        AND PARSE_DATE("%Y%m%d", "20251231")

